// MARK: - SecretsManager.swift
// Loads secrets from a non-versioned configuration file at runtime

import Foundation

enum SecretsError: Error, LocalizedStringError {
    case missingSecretsFile
    case missingKey(String)
    case invalidConfiguration
    
    var errorDescription: String? {
        switch self {
        case .missingSecretsFile:
            return "Secrets.plist not found. See README for setup instructions."
        case .missingKey(let key):
            return "Missing required key: \(key). Check Secrets.plist."
        case .invalidConfiguration:
            return "Invalid secrets configuration format."
        }
    }
}

final class SecretsManager {
    static let shared = SecretsManager()
    
    private var secrets: [String: Any] = [:]
    private var isLoaded = false
    
    private init() {
        loadSecrets()
    }
    
    private func loadSecrets() {
        // Option 1: Load from Secrets.plist (excluded from version control)
        if let path = Bundle.main.path(forResource: "Secrets", ofType: "plist"),
           let dict = NSDictionary(contentsOfFile: path) as? [String: Any] {
            secrets = dict
            isLoaded = true
            return
        }
        
        // Option 2: Load from environment variables (CI/CD friendly)
        var envSecrets: [String: Any] = [:]
        if let googleKey = ProcessInfo.processInfo.environment["GOOGLE_MAPS_API_KEY"] {
            envSecrets["GOOGLE_MAPS_API_KEY"] = googleKey
        }
        if let stripeKey = ProcessInfo.processInfo.environment["STRIPE_PUBLISHABLE_KEY"] {
            envSecrets["STRIPE_PUBLISHABLE_KEY"] = stripeKey
        }
        if !envSecrets.isEmpty {
            secrets = envSecrets
            isLoaded = true
