            secrets["GOOGLE_MAPS_API_KEY"] = googleKey
            secrets["STRIPE_PUBLISHABLE_KEY"] = stripeKey
            isLoaded = true
        }
    }
    
    var isConfigured: Bool {
        return isLoaded && !secrets.isEmpty
    }
    
    func googleMapsAPIKey() throws -> String {
        guard isLoaded else { throw SecretsError.missingSecretsFile }
        guard let key = secrets["GOOGLE_MAPS_API_KEY"] as? String, !key.isEmpty else {
            throw SecretsError.missingKey("GOOGLE_MAPS_API_KEY")
